#!/usr/bin/perl
use strict;
use warnings;
use CGI qw(:standard);
use CGI::Carp qw(fatalsToBrowser);
use File::Basename;
use File::Spec;

my $q = CGI->new();

print $q->header('text/html');
print $q->start_html(-title => 'Log File Viewer');

my $log_dir = '/var/log/myapp';

my $filename = $q->param('logfile');

if (!defined $filename || $filename eq '') {
    print $q->h1('Log File Viewer');
    print $q->p('Error: No log file specified. Please provide a logfile parameter.');
    print $q->end_html;
    exit 0;
}

# Security: Strip any directory components to prevent path traversal
# Only allow the bare filename, no path separators
$filename = fileparse($filename);

# Security: Reject filenames with path traversal attempts
if ($filename =~ /\.\./ || $filename =~ /[\/\\]/ || $filename eq '') {
    print $q->h1('Log File Viewer');
    print $q->p('Error: Invalid filename.');
    print $q->end_html;
    exit 0;
}

# Security: Only allow alphanumeric characters, dots, hyphens, and underscores
if ($filename !~ /^[a-zA-Z0-9._-]+$/) {
    print $q->h1('Log File Viewer');
    print $q->p('Error: Filename contains invalid characters.');
    print $q->end_html;
    exit 0;
}

# Security: Only allow .log and .txt extensions
if ($filename !~ /\.(log|txt)$/) {
    print $q->h1('Log File Viewer');
    print $q->p('Error: Only .log and .txt files are permitted.');
    print $q->end_html;
    exit 0;
}

# Build the full path safely using File::Spec
my $filepath = File::Spec->catfile($log_dir, $filename);

# Security: Resolve to absolute path and verify it's still within log_dir
my $abs_filepath = File::Spec->rel2abs($filepath);
my $abs_log_dir = File::Spec->rel2abs($log_dir);

if (index($abs_filepath, $abs_log_dir . '/') != 0) {
    print $q->h1('Log File Viewer');
    print $q->p('Error: Access denied. File is outside the allowed directory.');
    print $q->end_html;
    exit 0;
}

# Security: Ensure it's a regular file and not a symlink
if (-l $abs_filepath) {
    print $q->h1('Log File Viewer');
    print $q->p('Error: Symbolic links are not allowed.');
    print $q->end_html;
    exit 0;
}

if (!-f $abs_filepath) {
    print $q->h1('Log File Viewer');
    print $q->p('Error: File not found or is not a regular file.');
    print $q->end_html;
    exit 0;
}

if (!-r $abs_filepath) {
    print $q->h1('Log File Viewer');
    print $q->p('Error: File is not readable.');
    print $q->end_html;
    exit 0;
}

# Security: Use three-argument open with lexical filehandle in read-only mode
my $fh;
if (!open($fh, '<', $abs_filepath)) {
    print $q->h1('Log File Viewer');
    print $q->p('Error: Unable to open log file.');
    print $q->end_html;
    exit 0;
}

# Limit file size to prevent DoS (10 MB max)
my $max_size = 10 * 1024 * 1024;
my $file_size = -s $abs_filepath;

print $q->h1('Log File Viewer');
print $q->h2('File: ' . $q->escapeHTML($filename));
print $q->p('Size: ' . $file_size . ' bytes');

if ($file_size > $max_size) {
    print $q->p("Warning: File exceeds maximum display size of $max_size bytes. Showing first $max_size bytes only.");
}

print '<pre style="background-color: #f4f4f4; padding: 10px; border: 1px solid #ccc; overflow: auto; max-height: 600px;">';

my $bytes_read = 0;
while (my $line = <$fh>) {
    $bytes_read += length($line);
    if ($bytes_read > $max_size) {
        print $q->escapeHTML("[... truncated ...]");
        last;
